import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.apache.commons.text.StringEscapeUtils; // Import Apache Commons Text library for HTML escaping

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize and encode user input before outputting it
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input: " + sanitizedInput + "</h1>"); // Output sanitized input
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
